const weights = JSON.parse($('Get ICP Weights').item.json.value);
const d = $json;

const ind = (d.industry || d.category || '').toLowerCase();
let industryScore = 0;
for (const rule of weights.industry_rules || []) {
  if (rule.keywords.some(k => ind.includes(k))) { industryScore = rule.score; break; }
}
if (!industryScore) industryScore = weights.industry_default || 5;

let sizeScore = 0;
const emp = d.employeeCount;
if (emp !== null && emp !== undefined) {
  for (const rule of weights.size_rules || []) {
    if (emp >= rule.min && emp <= rule.max) { sizeScore = rule.score; break; }
  }
}

let revenueScore = 0;
const rev = d.revenueMm;
if (rev !== null && rev !== undefined) {
  for (const rule of weights.revenue_rules || []) {
    if (rev >= rule.min && rev <= rule.max) { revenueScore = rule.score; break; }
  }
}

const dmScore = 0;
const total = industryScore + sizeScore + revenueScore + dmScore;
const thresholds = weights.thresholds || { qualified: 70, review: 50 };
let status;
if (total >= thresholds.qualified) status = 'ICP_QUALIFIED';
else if (total >= thresholds.review) status = 'ICP_REVIEW_PENDING';
else status = 'ICP_DISQUALIFIED';

return { json: { companyId: d.id, scoreTotal: total, status, breakdown: { industry_fit: industryScore, company_size: sizeScore, revenue: revenueScore, decision_maker: dmScore } } };
